#import "WBRouteManager.h"
#import "WBRouteExpress.h"
#import "WBRouteActionManager.h"
#import "WBEventManager.h"

@interface WBRouteManager () <JUNRouter>

@property(nonatomic, strong) JUNRouteExpress *routeExpress;

@end

@implementation WBRouteManager

- (void)jun_routeBuild:(JUNRouteBuilder *)route {
    id<JUNRouter> rootVC = [WBAppManager getUIApplicationRootViewController];
    [route name:@"page" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        self.stashedDefaultHandler = nil;
        next(rootVC);
    }];
    [route name:@"action" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        WBRouteActionManager *actionManager = [WBRouteActionManager sharedManager];
        if (self.stashedDefaultHandler) {
            actionManager.stashedDefaultHandler = self.stashedDefaultHandler;
            self.stashedDefaultHandler = nil;
        }
        next(actionManager);
    }];
}

+ (instancetype)sharedManager {
    static WBRouteManager *manager = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        manager = [[self alloc] init];
    });
    return manager;
}

- (instancetype)init {
    if (self = [super init]) {
        JUNRouteExpress *routeExpress = [[WBRouteExpress alloc] initWithRouteMappingFile:@"route_mapping.plist" animated:true];
        routeExpress.scheme = @"webox";
        self.routeExpress = routeExpress;
    }
    return self;
}

- (void)performRoute:(NSURL *)url completion:(void (^ _Nullable)(id<JUNRouter> _Nonnull))completionHandler sourceInterface:(nullable NSString *)sourceInterface {
    [self logRouteEventWithURL:url sourceInterface:sourceInterface];
    if ([url.path isEqualToString:@"/action/popup"] && sourceInterface.length > 0) {
        NSURLComponents *components = [NSURLComponents componentsWithURL:url resolvingAgainstBaseURL:NO];
        NSMutableArray<NSURLQueryItem *> *queryItems = [components.queryItems mutableCopy] ?: [NSMutableArray new];
        NSURLQueryItem *sourceItem = [NSURLQueryItem queryItemWithName:@"sourceInterface" value:sourceInterface];
        [queryItems addObject:sourceItem];
        components.queryItems = queryItems;
        url = components.URL;
    }
    if ([url.path isEqualToString:@"/page/mine/CustomerServiceByWeChatSDK"]) {
        NSURLComponents *components = [NSURLComponents componentsWithURL:url resolvingAgainstBaseURL:NO];
        components.path = @"/action/CustomerServiceByWeChatSDK";
        url = components.URL;
    }
    if ([url.path isEqualToString:@"/page/mine/CustomerServiceByOldMethod"]) {
        NSURLComponents *components = [NSURLComponents componentsWithURL:url resolvingAgainstBaseURL:NO];
        components.path = @"/action/CustomerServiceByOldMethod";
        url = components.URL;
    }
    [self.routeExpress deliver:url toFirstRouter:self completion:completionHandler];
}

- (void)performRoute:(NSURL *)url sourceInterface:(nullable NSString *)sourceInterface {
    [self performRoute:url completion:nil sourceInterface:sourceInterface];
}

- (void)logRouteEventWithURL:(NSURL *)url sourceInterface:(nullable NSString *)sourceInterface {
    // NSDateFormatter
    NSDateFormatter *dateFormatter = [[NSDateFormatter alloc] init];
    [dateFormatter setDateFormat:@"yyyy-MM-dd HH:mm:ss"];
    [dateFormatter setTimeZone:[NSTimeZone systemTimeZone]];
    NSString *formattedDateString = [dateFormatter stringFromDate:[NSDate date]];

    // 对 url.query 进行 URL 解码
    NSString *decodedQuery = [url.query stringByRemovingPercentEncoding];
    id queryValue = decodedQuery; // 默认使用解码后的查询字符串

    if (decodedQuery && [decodedQuery hasPrefix:@"data="]) {
        // 提取 "data=" 后面的 JSON 字符串部分
        NSString *jsonString = [decodedQuery substringFromIndex:5];

        NSError *error;
        NSData *jsonDataBytes = [jsonString dataUsingEncoding:NSUTF8StringEncoding];
        id jsonObject = [NSJSONSerialization JSONObjectWithData:jsonDataBytes options:kNilOptions error:&error];

        if (jsonObject && !error) {
            queryValue = jsonObject;
        } else {
            NSLog(@"JSON Parsing Error: %@", error);
        }
    }

    // 构建日志上下文字典
    NSMutableDictionary *logContext = [@{
        @"applicationState": @([UIApplication sharedApplication].applicationState),
        @"networkConnected": @([[WBAppManager sharedManager] isNetworkConnected]),
        @"isVappRunning": @(vapp_is_running()),
        @"reqId": [NSUUID UUID].UUIDString, // 生成唯一请求ID
        @"time": formattedDateString ?: @"",
        @"scheme": url.scheme ?: @"",
        @"host": url.host ?: @"",
        @"route": url.path ?: @"",
        @"query": queryValue ?: @"",
        @"sourceInterface": sourceInterface ?: @"",
    } mutableCopy];

    // 事件记录
    [WBEventManager logAppRouteTrigger:logContext];
}


@end

